const ITEMS = ['Coffee Mug', 'Notebook', 'USB Cable', 'Desk Lamp', 'Water Bottle'];
const results = [];

for (const item of $input.all()) {
  const payload = item.json;
  const state =
    payload.body && typeof payload.body === 'object' ? payload.body : payload;
  const cycle = Number(state.cycle ?? 0);

  results.push({
    json: {
      cycle,
      order_id: 'ORD-' + String(Math.floor(10000 + Math.random() * 90000)),
      item: ITEMS[Math.floor(Math.random() * ITEMS.length)],
      quantity: Math.floor(Math.random() * 5) + 1,
      unit_price: Math.round((5 + Math.random() * 45) * 100) / 100,
      created_at: new Date().toISOString(),
    },
  });
}

return results;

const results = [];

for (const item of $input.all()) {
  const data = item.json;
  const subtotal = Math.round(data.quantity * data.unit_price * 100) / 100;
  results.push({ json: { ...data, subtotal } });
}

return results;

const TAX_RATE = 0.08;
const results = [];

for (const item of $input.all()) {
  const data = item.json;
  const tax_amount = Math.round(data.subtotal * TAX_RATE * 100) / 100;

  results.push({
    json: {
      ...data,
      tax_rate: TAX_RATE,
      tax_amount,
      total_before_discount: Math.round((data.subtotal + tax_amount) * 100) / 100,
    },
  });
}

return results;

const DISCOUNT_THRESHOLD = 40.0;
const DISCOUNT_PERCENT = 10;
const results = [];

for (const item of $input.all()) {
  const data = item.json;
  const total_before = data.total_before_discount;

  let discount_percent = 0;
  let discount_amount = 0;

  if (total_before >= DISCOUNT_THRESHOLD) {
    discount_percent = DISCOUNT_PERCENT;
    discount_amount =
      Math.round(total_before * (discount_percent / 100) * 100) / 100;
  }

  results.push({
    json: {
      ...data,
      discount_percent,
      discount_amount,
      final_total: Math.round((total_before - discount_amount) * 100) / 100,
    },
  });
}

return results;

const results = [];

for (const item of $input.all()) {
  const data = item.json;

  const lines = [
    `--- RECEIPT ${data.order_id} ---`,
    `Item:     ${data.item}`,
    `Qty:      ${data.quantity} x $${data.unit_price.toFixed(2)}`,
    `Subtotal: $${data.subtotal.toFixed(2)}`,
    `Tax (${Math.round(data.tax_rate * 100)}%):    $${data.tax_amount.toFixed(2)}`,
  ];

  if (data.discount_amount > 0) {
    lines.push(
      `Discount (${data.discount_percent}%): -$${data.discount_amount.toFixed(2)}`
    );
  }

  lines.push(`TOTAL:    $${data.final_total.toFixed(2)}`);
  lines.push('------------------------');

  results.push({ json: { ...data, receipt: lines.join('\n') } });
}

return results;

const results = [];

for (const item of $input.all()) {
  const data = item.json;
  const cycle = Number(data.cycle ?? 0);
  const next_cycle = cycle + 1;

  results.push({
    json: {
      cycle,
      next_cycle,
      last_order_id: data.order_id,
      last_final_total: data.final_total,
      last_receipt: data.receipt,
      stage: 'loop_ready',
      loop_payload: {
        cycle: next_cycle,
        running: true,
      },
    },
  });
}

return results;
